int rev[15];

int solve(ll x) {
  if (x % 10 == 0) {
    return 0;
  }

  ll dummy = x;
  int ptr = 14;

  while (x > 0) {
    int rem = x % 10;
    x /= 10;
    rev[ptr] = rem;
    ptr--;
  }

  int dyszka = 1;
  ll sum = dummy;
  ll sum2 = 0;

  for (int i = 1 + ptr; i < 15; i++) {
    sum2 += (ll)(dyszka * rev[i]);
    dyszka *= 10;
  }

  sum = sum + sum2;

  if (sum == 0) return 0;

  while (sum > 0) {
    int remain = sum % 10;
    if (remain % 2 == 0) {
      return 0;
    }
    sum /= 10;
  }
  return 1;
}

int main() {
  ll k;
  scanf("%lld", &k);
  ll cnt = 0;
  ll start_point = 1;

  if (k >= 1000000) {
    ll base_point = (k / 1000000) * 1000000;
    int index = (base_point / 1000000) - 1;

    if (index >= 0) {
      cnt = precomputed_counts[index];
      start_point = base_point + 1;
    }
  }

  for (ll i = start_point; i <= k; i++) {
    cnt += solve(i);
  }
  printf("%lld", cnt);
}
